/**
 * Parse a subtitle filename of the form
 *   "{base}.{lang}[.{modifier}...].srt"
 * where each modifier is one of: "hi" (hearing-impaired) or "auto" (auto-generated).
 *
 * Modifiers are order-independent: "name.en.auto.hi.srt" and "name.en.hi.auto.srt"
 * both parse the same way.
 *
 * Returns null if the filename doesn't look like a subtitle file.
 *
 * @param {string} filename - Bare filename (no path)
 * @param {Object} [langMap] - Optional code → display-name map
 * @returns {{ langCode, langName, subtitleKey, isHearingImpaired, isAutoGenerated } | null}
 */
export function parseSubtitleFilename(filename, langMap = {}) {
  const parts = filename.split('.');
  const srtIndex = parts.lastIndexOf('srt');
  if (srtIndex < 1) return null;

  const modifiers = new Set();
  let cursor = srtIndex - 1;
  while (cursor > 0 && (parts[cursor] === 'hi' || parts[cursor] === 'auto')) {
    modifiers.add(parts[cursor]);
    cursor--;
  }
  const langCode = parts[cursor];
  const isHearingImpaired = modifiers.has('hi');
  const isAutoGenerated = modifiers.has('auto');
  const langName = langMap[langCode] || langCode;

  let subtitleKey = langName;
  if (isHearingImpaired) subtitleKey += ' Hearing Impaired';
  if (isAutoGenerated) subtitleKey += ' - Auto Generated';

  return { langCode, langName, subtitleKey, isHearingImpaired, isAutoGenerated };
}
